18	export function useAgents(workspaceId: string): UseRPCQueryResult<AgentSessionDTO[]> {
19	  const query = useRPCQuery<AgentSessionDTO[]>("listAgentSessions", { workspaceId }, [workspaceId]);
20	  useRPCSubscription<{ sessionId: string; status: AgentStatus; error?: string }>(
21	    "agentStatusChange",
22	    () => {
23	      query.refetch();
24	    },
25	    [workspaceId],
26	  );
27	  return query;
28	}
29	
30	export function useStartAgent(): UseRPCMutationResult<{ sessionId: string }, StartAgentInput> {
31	  return useRPCMutation<{ sessionId: string }, StartAgentInput>("startAgent");
32	}
33	
34	export function useStopAgent(): UseRPCMutationResult<{ success: boolean }, StopAgentInput> {
35	  return useRPCMutation<{ success: boolean }, StopAgentInput>("stopAgent");
36	}
37	
38	export function useAgentOutput(sessionId: string | null): AgentUpdateDTO[] {
39	  const [chunks, setChunks] = useState<AgentUpdateDTO[]>([]);
40	
41	  // biome-ignore lint/correctness/useExhaustiveDependencies: reset chunks when session changes
42	  useEffect(() => {
