import type { AgentUpdateDTO } from "shared/rpc";
import { AgentBinaryNotFoundError } from "../../../utils/errors";
import { createLogger } from "../../../utils/logger";
import type { AgentBackend, AgentBackendExitInfo } from "../agent.types";
import { type JsonRpcPeer, connectJsonRpc } from "./jsonrpc-stdio";

export interface CodexBackendConfig {
  sessionId: string;
  binaryPath?: string;
  onExit?: (info: AgentBackendExitInfo) => void;
}

interface CodexThreadStartResult {
  threadId: string;
}

interface CodexItemStartedParams {
  itemId: string;
  itemType: string;
  title?: string;
}
interface CodexAgentMessageDeltaParams {
  delta: string;
}
interface CodexItemCompletedParams {
  itemId: string;
  itemType: string;
}

export function mapCodexNotification(method: string, params: unknown): AgentUpdateDTO | null {
  const p = (params ?? {}) as Record<string, unknown>;
  if (method === "item/started") {
    const ev = p as unknown as CodexItemStartedParams;
    if (ev.itemType && ev.itemType !== "agentMessage") {
      return {
        kind: "tool_call",
        toolCallId: ev.itemId,
        title: ev.title ?? ev.itemType,
        toolKind: ev.itemType,
        status: "in_progress",
      };
    }
  } else if (method === "item/agentMessage/delta") {
    const ev = p as unknown as CodexAgentMessageDeltaParams;
    if (ev.delta) return { kind: "message", text: ev.delta };
  } else if (method === "item/completed") {
    const ev = p as unknown as CodexItemCompletedParams;
    if (ev.itemType && ev.itemType !== "agentMessage") {
      return {
        kind: "tool_call_update",
        toolCallId: ev.itemId,
        status: "completed",
        title: null,
      };
    }
  }
  return null;
}

export function createCodexBackend(config: CodexBackendConfig): AgentBackend {
  const log = createLogger("codex-backend");
  const binaryName = config.binaryPath ?? process.env.PILOTO_CODEX_BIN ?? "codex";

  let peer: JsonRpcPeer | null = null;
  let threadId: string | null = null;
  let onUpdateCb: ((update: AgentUpdateDTO) => void) | null = null;

  function handleNotification(method: string, params: unknown): void {
    const update = mapCodexNotification(method, params);
    if (update) onUpdateCb?.(update);
  }

  async function startTurn(prompt: string): Promise<void> {
    if (!peer || !threadId) return;
    await peer.request("turn/start", { threadId, input: prompt });
  }

  return {
    name: "codex",
    async start({ workingDir, prompt }) {
      const binary = Bun.which(binaryName);
      if (!binary) throw new AgentBinaryNotFoundError(binaryName);

      peer = connectJsonRpc({
        binary,
        args: ["app-server"],
        cwd: workingDir,
        onStderr: (chunk) => log.debug(`codex stderr: ${chunk.trimEnd()}`),
        onExit: (code, signal) => {
          log.info(`codex process exited code=${code} signal=${signal}`);
          config.onExit?.({ code, signal });
        },
      });
      peer.onNotification(handleNotification);

      await peer.request("initialize", {});
      peer.notify("initialized", {});

      const thread = await peer.request<CodexThreadStartResult>("thread/start", {
        cwd: workingDir,
      });
      threadId = thread.threadId;

      if (prompt) {
        void startTurn(prompt).catch((err: Error) => {
          log.error(`codex turn/start failed: ${err.message}`);
        });
      }

      return { sessionId: config.sessionId };
    },
    async sendPrompt(prompt: string) {
      if (!peer || !threadId) throw new Error("codex backend not started");
      await startTurn(prompt);
    },
    async stop() {
      if (!peer) return;
      await peer.shutdown(5_000);
      peer = null;
      threadId = null;
    },
    onUpdate(cb) {
      onUpdateCb = cb;
    },
  };
}

import { useCallback, useEffect, useState } from "react";
import type { AgentBackendName, AgentSessionDTO, AgentStatus, AgentUpdateDTO } from "shared/rpc";
import { type UseRPCMutationResult, useRPCMutation } from "./use-rpc-mutation";
import { type UseRPCQueryResult, useRPCQuery } from "./use-rpc-query";
import { useRPCSubscription } from "./use-rpc-subscription";

export interface StartAgentInput extends Record<string, unknown> {
  workspaceId: string;
  worktreeId?: string;
  backend: AgentBackendName;
  prompt?: string;
}

export interface StopAgentInput extends Record<string, unknown> {
  sessionId: string;
}

export function useAgents(workspaceId: string): UseRPCQueryResult<AgentSessionDTO[]> {
  const query = useRPCQuery<AgentSessionDTO[]>("listAgentSessions", { workspaceId }, [workspaceId]);
  useRPCSubscription<{ sessionId: string; status: AgentStatus; error?: string }>(
    "agentStatusChange",
    () => {
      query.refetch();
    },
    [workspaceId],
  );
  return query;
}

export function useStartAgent(): UseRPCMutationResult<{ sessionId: string }, StartAgentInput> {
  return useRPCMutation<{ sessionId: string }, StartAgentInput>("startAgent");
}

export function useStopAgent(): UseRPCMutationResult<{ success: boolean }, StopAgentInput> {
  return useRPCMutation<{ success: boolean }, StopAgentInput>("stopAgent");
}

export function useAgentOutput(sessionId: string | null): AgentUpdateDTO[] {
  const [chunks, setChunks] = useState<AgentUpdateDTO[]>([]);

  // biome-ignore lint/correctness/useExhaustiveDependencies: reset chunks when session changes
  useEffect(() => {
    setChunks([]);
  }, [sessionId]);

  const onOutput = useCallback(
    (payload: { sessionId: string; chunk: AgentUpdateDTO }) => {
      if (!sessionId || payload.sessionId !== sessionId) return;
      setChunks((prev) => [...prev, payload.chunk]);
    },
    [sessionId],
  );

  useRPCSubscription<{ sessionId: string; chunk: AgentUpdateDTO }>("agentOutput", onOutput, [
    sessionId,
  ]);

  return chunks;
}

import type { AgentUpdateDTO } from "shared/rpc";
import { AgentBinaryNotFoundError } from "../../../utils/errors";
import { createLogger } from "../../../utils/logger";
import type { AgentBackend, AgentBackendExitInfo } from "../agent.types";
import { type LineStreamHandle, spawnLineStream } from "./jsonrpc-stdio";

export interface ClaudeBackendConfig {
  sessionId: string;
  binaryPath?: string;
  onExit?: (info: AgentBackendExitInfo) => void;
}

interface StreamJsonTextBlock {
  type: "text";
  text: string;
}
interface StreamJsonThinkingBlock {
  type: "thinking";
  thinking: string;
}
interface StreamJsonToolUseBlock {
  type: "tool_use";
  id: string;
  name: string;
  input: unknown;
}
interface StreamJsonToolResultBlock {
  type: "tool_result";
  tool_use_id: string;
  content?: unknown;
  is_error?: boolean;
}
type StreamJsonBlock =
  | StreamJsonTextBlock
  | StreamJsonThinkingBlock
  | StreamJsonToolUseBlock
  | StreamJsonToolResultBlock;

interface StreamJsonAssistantEvent {
  type: "assistant";
  message: { content: StreamJsonBlock[] };
}
interface StreamJsonUserEvent {
  type: "user";
  message: { content: StreamJsonBlock[] };
}

export function createClaudeBackend(config: ClaudeBackendConfig): AgentBackend {
  const log = createLogger("claude-backend");
  const binaryName = config.binaryPath ?? process.env.PILOTO_CLAUDE_BIN ?? "claude";

  let stream: LineStreamHandle | null = null;
  let onUpdateCb: ((update: AgentUpdateDTO) => void) | null = null;

  function emit(update: AgentUpdateDTO): void {
    onUpdateCb?.(update);
  }

  function handleLine(line: string): void {
    let event: { type?: string } & Record<string, unknown>;
    try {
      event = JSON.parse(line);
    } catch {
      return;
    }
    if (event.type === "assistant") {
      const ev = event as unknown as StreamJsonAssistantEvent;
      for (const block of ev.message.content) {
        if (block.type === "text") {
          emit({ kind: "message", text: block.text });
        } else if (block.type === "thinking") {
          emit({ kind: "thought", text: block.thinking });
        } else if (block.type === "tool_use") {
          emit({
            kind: "tool_call",
            toolCallId: block.id,
            title: block.name,
            toolKind: "other",
            status: "in_progress",
          });
        }
      }
    } else if (event.type === "user") {
      const ev = event as unknown as StreamJsonUserEvent;
      for (const block of ev.message.content) {
        if (block.type === "tool_result") {
          emit({
            kind: "tool_call_update",
            toolCallId: block.tool_use_id,
            status: block.is_error ? "failed" : "completed",
            title: null,
          });
        }
      }
    }
  }

  function writeUserMessage(text: string): void {
    if (!stream) return;
    const payload = {
      type: "user",
      message: { role: "user", content: [{ type: "text", text }] },
    };
    stream.writeLine(JSON.stringify(payload));
  }

  return {
    name: "claude",
    async start({ workingDir, prompt }) {
      const binary = Bun.which(binaryName);
      if (!binary) throw new AgentBinaryNotFoundError(binaryName);

      stream = spawnLineStream({
        binary,
        args: [
          "-p",
          "--output-format",
          "stream-json",
          "--input-format",
          "stream-json",
          "--verbose",
          "--session-id",
          config.sessionId,
        ],
        cwd: workingDir,
        onLine: handleLine,
        onStderr: (chunk) => log.debug(`claude stderr: ${chunk.trimEnd()}`),
        onExit: (code, signal) => {
          log.info(`claude process exited code=${code} signal=${signal}`);
          config.onExit?.({ code, signal });
        },
      });

      if (prompt) writeUserMessage(prompt);
      return { sessionId: config.sessionId };
    },
    async sendPrompt(prompt: string) {
      if (!stream) throw new Error("claude backend not started");
      writeUserMessage(prompt);
    },
    async stop() {
      if (!stream) return;
      await stream.shutdown(5_000);
      stream = null;
    },
    onUpdate(cb) {
      onUpdateCb = cb;
    },
  };
}

import { randomUUID } from "node:crypto";
import { asc, eq } from "drizzle-orm";
import type { AgentBackendName, AgentStatus, AgentUpdateDTO } from "shared/rpc";
import { getDb } from "../../db/database";
import { activeWorktrees, agentSessions, workspaceRepos } from "../../db/schema";
import { NotFoundError, ValidationError } from "../../utils/errors";
import { createLogger } from "../../utils/logger";
import type {
  AgentBackend,
  AgentSessionRow,
  AgentStatusChange,
  StartAgentInput,
} from "./agent.types";
import { createClaudeBackend } from "./backends/claude.backend";
import { createCodexBackend } from "./backends/codex.backend";

const log = createLogger("agent");

type AgentUpdateListener = (payload: { sessionId: string; chunk: AgentUpdateDTO }) => void;
type AgentStatusListener = (payload: AgentStatusChange) => void;

let updateListener: AgentUpdateListener | null = null;
let statusListener: AgentStatusListener | null = null;

export function setAgentUpdateNotifier(listener: AgentUpdateListener | null): void {
  updateListener = listener;
}

export function setAgentStatusNotifier(listener: AgentStatusListener | null): void {
  statusListener = listener;
}

interface RegistryEntry {
  backend: AgentBackend;
  workspaceId: string;
  worktreeId: string | null;
  stopping: boolean;
}

const registry = new Map<string, RegistryEntry>();

function isBackendName(v: string): v is AgentBackendName {
  return v === "claude" || v === "codex";
}

function updateSessionStatus(sessionId: string, status: AgentStatus, errorMessage?: string): void {
  const db = getDb();
  db.update(agentSessions)
    .set({
      status,
      errorMessage: errorMessage ?? null,
      updatedAt: new Date().toISOString(),
    })
    .where(eq(agentSessions.id, sessionId))
    .run();
  statusListener?.({ sessionId, status, error: errorMessage });
}

function setWorktreeAgentBinding(worktreeId: string | null, sessionId: string | null): void {
  if (!worktreeId) return;
  const db = getDb();
  db.update(activeWorktrees)
    .set({ agentSessionId: sessionId, updatedAt: new Date().toISOString() })
    .where(eq(activeWorktrees.id, worktreeId))
    .run();
}

function resolveWorkingDir(input: StartAgentInput): string {
  const db = getDb();
  if (input.worktreeId) {
    const worktree = db
      .select()
      .from(activeWorktrees)
      .where(eq(activeWorktrees.id, input.worktreeId))
      .get();
    if (!worktree) throw new NotFoundError("ActiveWorktree", input.worktreeId);
    return worktree.path;
  }

  const firstRepo = db
    .select()
    .from(workspaceRepos)
    .where(eq(workspaceRepos.workspaceId, input.workspaceId))
    .orderBy(asc(workspaceRepos.order))
    .get();
  if (!firstRepo) {
    throw new ValidationError(
      `Workspace ${input.workspaceId} has no repos; cannot start an agent without a working directory`,
    );
  }
  return firstRepo.path;
}

function handleBackendExit(sessionId: string, code: number | null): void {
  const entry = registry.get(sessionId);
  if (!entry || entry.stopping) return;
  entry.stopping = true;
  setWorktreeAgentBinding(entry.worktreeId, null);
  const status: AgentStatus = code === 0 ? "stopped" : "error";
  const message = code === 0 ? undefined : `agent process exited with code ${code}`;
  updateSessionStatus(sessionId, status, message);
  registry.delete(sessionId);
}

function instantiateBackend(backend: AgentBackendName, sessionId: string): AgentBackend {
  const onExit = ({ code }: { code: number | null }) => handleBackendExit(sessionId, code);
  if (backend === "claude") {
    return createClaudeBackend({ sessionId, onExit });
  }
  return createCodexBackend({ sessionId, onExit });
}

export async function startAgent(input: StartAgentInput): Promise<{ sessionId: string }> {
  if (!isBackendName(input.backend)) {
    throw new ValidationError(`Unsupported agent backend: ${input.backend}`);
  }

  const workingDir = resolveWorkingDir(input);
  const sessionId = randomUUID();
  const now = new Date().toISOString();
  const db = getDb();

  db.insert(agentSessions)
    .values({
      id: sessionId,
      workspaceId: input.workspaceId,
      worktreeId: input.worktreeId ?? null,
      backend: input.backend,
      status: "running",
      prompt: input.prompt ?? null,
      errorMessage: null,
      createdAt: now,
      updatedAt: now,
    })
    .run();

  let backend: AgentBackend;
  try {
    backend = instantiateBackend(input.backend, sessionId);
    backend.onUpdate((update) => {
      updateListener?.({ sessionId, chunk: update });
    });
    await backend.start({ workingDir, prompt: input.prompt ?? "" });
  } catch (err) {
    const message = err instanceof Error ? err.message : String(err);
    updateSessionStatus(sessionId, "error", message);
    log.error(`startAgent failed for session ${sessionId}: ${message}`);
    throw err;
  }

  registry.set(sessionId, {
    backend,
    workspaceId: input.workspaceId,
    worktreeId: input.worktreeId ?? null,
    stopping: false,
  });
  setWorktreeAgentBinding(input.worktreeId ?? null, sessionId);
  statusListener?.({ sessionId, status: "running" });

  return { sessionId };
}

export async function stopAgent(sessionId: string): Promise<{ success: boolean }> {
  const entry = registry.get(sessionId);
  if (!entry) {
    const db = getDb();
    const row = db.select().from(agentSessions).where(eq(agentSessions.id, sessionId)).get();
    if (!row) throw new NotFoundError("AgentSession", sessionId);
    if (row.status === "running") {
      setWorktreeAgentBinding(row.worktreeId, null);
      updateSessionStatus(sessionId, "stopped");
    }
    return { success: true };
  }

  entry.stopping = true;
  try {
    await entry.backend.stop();
  } catch (err) {
    const message = err instanceof Error ? err.message : String(err);
    log.warn(`stopAgent backend.stop threw: ${message}`);
  }

  registry.delete(sessionId);
  setWorktreeAgentBinding(entry.worktreeId, null);
  updateSessionStatus(sessionId, "stopped");
  return { success: true };
}

export function listAgentSessions(workspaceId: string): AgentSessionRow[] {
  const db = getDb();
  return db.select().from(agentSessions).where(eq(agentSessions.workspaceId, workspaceId)).all();
}

export function getAgentSession(sessionId: string): AgentSessionRow {
  const db = getDb();
  const row = db.select().from(agentSessions).where(eq(agentSessions.id, sessionId)).get();
  if (!row) throw new NotFoundError("AgentSession", sessionId);
  return row;
}

import { createHash } from "node:crypto";
import type { BunSQLiteDatabase } from "drizzle-orm/bun-sqlite";
